// src/pages/SplashPage.js
import { useEffect } from 'react';
import { useNavigate } from 'react-router-dom'; // if using react-router
import './SplashPage.css';
import wLogo from '../assets/wlogo.png'; // Adjust path based on where your image is located

function SplashPage() {
  const navigate = useNavigate();

  useEffect(() => {
    const timer = setTimeout(() => {
      // Navigate to home page after splash
      navigate('/home'); // or window.location.href = '/home' if not using router
    }, 3000);

    return () => clearTimeout(timer);
  }, [navigate]);

  return (
    <div className="splash-container">
      <div className="splash-content">
        {/* Your Wattpad logo image */}
        <img 
          src={wLogo} 
          alt="Wattpad Logo" 
          className="wattpad-logo-img"
        />
        
        {/* Optional tagline */}
        <p className="tagline">Stories you'll love</p>
        
        {/* Loading animation */}
        <div className="loader"></div>
      </div>
    </div>
  );
}

export default SplashPage;
